9: import { M_BEACON, type Room, Thread, type MatrixEvent, EventType, type MatrixClient } from "matrix-js-sdk/src/matrix";
10: import { logger } from "matrix-js-sdk/src/logger";
11: 
12: import shouldHideEvent from "./shouldHideEvent";
13: import { haveRendererForEvent } from "./events/EventTileFactory";
14: import { RoomNotifState, getRoomNotifsState } from "./RoomNotifs";
15: 
16: /**
17:  * Returns true if this event arriving in a room should affect the room's
18:  * count of unread messages
19:  *
20:  * @param client The Matrix Client instance of the logged-in user
21:  * @param {Object} ev The event
22:  * @returns {boolean} True if the given event should affect the unread message count
23:  */
24: export function eventTriggersUnreadCount(client: MatrixClient, ev: MatrixEvent): boolean {
25:     if (ev.getSender() === client.getSafeUserId()) {
26:         return false;
27:     }
28: 
29:     switch (ev.getType()) {
30:         case EventType.RoomMember:
31:         case EventType.RoomThirdPartyInvite:
32:         case EventType.CallAnswer:
33:         case EventType.CallHangup:
34:         case EventType.RoomCanonicalAlias:
35:         case EventType.RoomServerAcl:
36:         case M_BEACON.name:
37:         case M_BEACON.altName:
38:             return false;
39:     }
40: 
41:     if (ev.isRedacted()) return false;
42:     try {
43:         return haveRendererForEvent(ev, client, false /* hidden messages should never trigger unread counts anyways */);
44:     } catch (e) {
45:         console.warn("Error determining if event should trigger unread count", e);
46:         return false; // If we can't determine if the event should trigger an unread count, assume it does not.
47:     }
48: }
49: 
50: export function doesRoomHaveUnreadMessages(room: Room, includeThreads: boolean): boolean {
51:     const toCheck: Array<Room | Thread> = [room];
52:     if (includeThreads) {
53:         toCheck.push(...room.getThreads());
54:     }
55: 
56:     for (const withTimeline of toCheck) {
57:         if (doesTimelineHaveUnreadMessages(room, withTimeline.timeline)) {
58:             // We found an unread, so the room is unread
59:             return true;
60:         }
61:     }
62: 
63:     // If we got here then no timelines were found with unread messages.
64:     return false;
65: }
66: 
67: function doesTimelineHaveUnreadMessages(room: Room, timeline: Array<MatrixEvent>): boolean {
68:     // The room is a space, let's ignore it
69:     if (room.isSpaceRoom()) return false;
70: 
71:     const myUserId = room.client.getSafeUserId();
72:     const latestImportantEventId = findLatestImportantEvent(room.client, timeline)?.getId();
73:     if (latestImportantEventId) {
74:         return !room.hasUserReadEvent(myUserId, latestImportantEventId);
75:     } else {
76:         // We couldn't find an important event to check - check the unimportant ones.
77:         const earliestUnimportantEventId = timeline.at(0)?.getId();
78:         if (!earliestUnimportantEventId) {
79:             // There are no events in this timeline - it is uninitialised, so we
80:             // consider it read
81:             return false;
82:         } else if (room.hasUserReadEvent(myUserId, earliestUnimportantEventId)) {
83:             // Some of the unimportant events are read, and there are no
84:             // important ones after them, so we've read everything.
85:             return false;
86:         } else {
87:             // We have events. and none of them are read.  We must guess that
88:             // the timeline is unread, because there could be older unread
89:             // important events that we don't have loaded.
90:             logger.warn("Falling back to unread room because of no read receipt or counting message found", {
91:                 roomId: room.roomId,
92:                 earliestUnimportantEventId: earliestUnimportantEventId,
93:             });
94:             return true;
95:         }
96:     }
97: }
98: 
99: /**
100:  * Returns true if this room has unread threads.
101:  * @param room The room to check
102:  * @returns {boolean} True if the given room has unread threads
103:  */
104: export function doesRoomHaveUnreadThreads(room: Room): boolean {
105:     if (getRoomNotifsState(room.client, room.roomId) === RoomNotifState.Mute) {
106:         // No unread for muted rooms, nor their threads
107:         // NB. This logic duplicated in RoomNotifs.determineUnreadState
108:         return false;
109:     }
110: 
111:     for (const thread of room.getThreads()) {
112:         if (doesTimelineHaveUnreadMessages(room, thread.timeline)) {
113:             // We found an unread, so the room has an unread thread
114:             return true;
115:         }
116:     }
117: 
118:     // If we got here then no threads were found with unread messages.
119:     return false;
120: }
121: 
122: export function doesRoomOrThreadHaveUnreadMessages(roomOrThread: Room | Thread): boolean {
123:     const room = roomOrThread instanceof Thread ? roomOrThread.room : roomOrThread;
124:     const events = roomOrThread instanceof Thread ? roomOrThread.timeline : room.getLiveTimeline().getEvents();
125:     return doesTimelineHaveUnreadMessages(room, events);
126: }
127: 
128: /**
129:  * Look backwards through the timeline and find the last event that is
130:  * "important" in the sense of isImportantEvent.
131:  *
132:  * @returns the latest important event, or null if none were found
133:  */
134: function findLatestImportantEvent(client: MatrixClient, timeline: Array<MatrixEvent>): MatrixEvent | null {
135:     for (let index = timeline.length - 1; index >= 0; index--) {
136:         const event = timeline[index];
137:         if (isImportantEvent(client, event)) {
138:             return event;
139:         }
140:     }
141:     return null;
142: }
143: 
144: /**
145:  * Given this event does not have a receipt, is it important enough to make
146:  * this room unread?
147:  */
148: function isImportantEvent(client: MatrixClient, event: MatrixEvent): boolean {
149:     return !shouldHideEvent(event) && eventTriggersUnreadCount(client, event);
150: }
