            return true;
        }
    }

    // If we got here then no threads were found with unread messages.
    return false;
}

export function doesRoomOrThreadHaveUnreadMessages(roomOrThread: Room | Thread): boolean {
    const events = roomOrThread instanceof Thread ? roomOrThread.timeline : roomOrThread.getLiveTimeline().getEvents();
    return doesTimelineHaveUnreadMessages(roomOrThread, events);
